  1→const rule = {
  2→	meta: {
  3→		type: 'suggestion',
  4→		docs: {
  5→			description: 'Require custom functions to use single object parameter',
  6→			category: 'Best Practices',
  7→		},
  8→		schema: [],
  9→		messages: {
 10→			requireObjectParam:
 11→				'Custom functions must use a single object destructuring parameter',
 12→		},
 13→	},
 14→	create(context) {
 15→		const lifecycleHooks = [
 16→			'onModuleInit',
 17→			'onApplicationBootstrap',
 18→			'onModuleDestroy',
 19→			'onApplicationShutdown',
 20→			'configure',
 21→			'use',
 22→			'catch',
 23→			'intercept',
 24→			'canActivate',
 25→			'validate',
 26→			'transform',
 27→			'run',
 28→		];
 29→
 30→		const testingCallbacks = [
 31→			'it',
 32→			'test',
 33→			'describe',
 34→			'beforeEach',
 35→			'afterEach',
 36→			'beforeAll',
 37→			'afterAll',
 38→		];
 39→
 40→		const nestjsDecorators = [
 41→			'Get',
 42→			'Post',
 43→			'Put',
 44→			'Delete',
 45→			'Patch',
 46→			'Options',
 47→			'Head',
 48→			'All',
 49→			'UseGuards',
 50→			'UseInterceptors',
 51→			'UsePipes',
 52→			'SetMetadata',
 53→			'Option',
 54→		];
 55→
 56→		const explicitSkipFunctions = ['transform'];
 57→
 58→		function hasNestJSDecorator(node) {
 59→			const parent = node.parent;
 60→			if (parent?.type === 'MethodDefinition' && parent.decorators) {
 61→				return parent.decorators.some((decorator) => {
 62→					const dec = decorator;
 63→					if (dec.expression.type === 'CallExpression') {
 64→						const callExpr = dec.expression;
 65→						const callee = callExpr.callee;
 66→						if (callee.type === 'Identifier') {
 67→							return nestjsDecorators.includes(callee.name);
 68→						}
 69→					}
 70→					return false;
 71→				});
 72→			}
 73→			return false;
 74→		}
 75→
 76→		function isFrameworkMethod(node) {
 77→			const parent = node.parent;
 78→
 79→			if (parent?.type === 'MethodDefinition') {
 80→				if (parent.kind === 'constructor') {
 81→					return true;
 82→				}
 83→
 84→				const key = parent.key;
 85→				if (key?.type === 'Identifier' && lifecycleHooks.includes(key.name)) {
 86→					return true;
 87→				}
 88→
 89→				if (hasNestJSDecorator(node)) {
 90→					return true;
 91→				}
 92→			}
 93→
 94→			return false;
 95→		}
 96→
 97→		function isTestingCallback(node) {
 98→			const parent = node.parent;
 99→
100→			if (parent?.type === 'CallExpression') {
101→				const callee = parent.callee;
102→				if (callee.type === 'Identifier' && testingCallbacks.includes(callee.name)) {
103→					return true;
104→				}
105→			}
106→
107→			return false;
108→		}
109→
110→		function isCallbackFunction(node) {
111→			const parent = node.parent;
112→
113→			if (!parent) return false;
114→
115→			if (isTestingCallback(node)) {
116→				return true;
117→			}
118→
119→			if (parent.type === 'CallExpression' || parent.type === 'NewExpression') {
120→				const callExpr = parent;
121→				if (callExpr.arguments.some((arg) => arg === node)) {
122→					return true;
123→				}
124→			}
125→
126→			if (parent.type === 'ArrayExpression') {
127→				return true;
128→			}
129→
130→			if (parent.type === 'Property') {
131→				const prop = parent;
132→				if (prop.value === node) {
133→					const grandParent = prop.parent;
134→					if (grandParent?.type === 'ObjectExpression') {
135→						const greatGrandParent = grandParent.parent;
136→						if (greatGrandParent?.type === 'CallExpression') {
137→							return true;
138→						}
139→					}
140→				}
141→			}
142→
143→			return false;
144→		}
145→
146→		function checkFunction(node) {
147→			if (isCallbackFunction(node) || isFrameworkMethod(node)) {
148→				return;
149→			}
150→
151→			const funcName =
152→				node.id?.name ??
153→				(node.parent?.type === 'MethodDefinition' ? node.parent.key?.name : undefined);
154→
155→			if (funcName && explicitSkipFunctions.includes(funcName)) {
156→				return;
157→			}
158→
159→			const params = node.params;
160→
161→			if (params.length === 0) {
162→				return;
163→			}
164→
165→			if (params.length === 1 && params[0]?.type === 'RestElement') {
166→				return;
167→			}
168→
169→			if (params.length === 1 && params[0]?.type === 'AssignmentPattern') {
170→				return;
171→			}
172→
173→			const hasValidObjectParam =
174→				params.length === 1 && params[0]?.type === 'ObjectPattern';
175→
176→			if (!hasValidObjectParam) {
177→				context.report({
178→					node: node,
179→					messageId: 'requireObjectParam',
180→				});
181→			}
182→		}
183→
184→		return {
185→			FunctionDeclaration(node) {
186→				checkFunction(node);
187→			},
188→			FunctionExpression(node) {
189→				const funcNode = node;
190→				if (funcNode.parent?.type === 'MethodDefinition') {
191→					return;
192→				}
193→				checkFunction(funcNode);
194→			},
195→			ArrowFunctionExpression(node) {
196→				checkFunction(node);
197→			},
198→			MethodDefinition(node) {
199→				const methodNode = node;
200→				checkFunction(methodNode.value);
201→			},
202→		};
203→	},
204→};
205→
206→module.exports = rule;
